mapper.select:
SELECT c.*, s.name AS student_name, t.name AS teacher_name, a.title AS activity_title FROM certificate c LEFT JOIN sys_user s ON c.student_id = s.id LEFT JOIN sys_user t ON c.teacher_id = t.id LEFT JOIN activity a ON c.activity_id = a.id
AND c.student_id = #{param.studentId} AND c.type = #{param.type}
ORDER BY c.obtain_time DESC
